"use client";

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { FadeIn, StaggerContainer, StaggerItem } from '@/components/animations/MotionUtils';
import { DashboardCard, DashboardChart } from '@/components/dashboard/OrbitComponents';
import { apiClient, ApiError } from '@/lib/apiClient';
import { useAuth } from '@/lib/authContext';

interface AdminStats {
  totalCourses: number;
  totalMaterials: number;
  totalApplications: number;
  totalResults: number;
}

export default function AdminDashboardPage() {
  const router = useRouter();
  const { user: authUser, isLoading: authLoading } = useAuth();
  const [stats, setStats] = useState<AdminStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!authLoading && (!authUser || authUser.role !== 'ADMIN')) {
      router.push('/login');
    }
  }, [authUser, authLoading, router]);

  useEffect(() => {
    if (!authUser || authUser.role !== 'ADMIN') return;
    const fetchData = async () => {
      try {
        const data = await apiClient.get<AdminStats>('/admin/stats');
        setStats(data);
      } catch (err) {
         setError('Failed to load administrative metrics.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [authUser, router]);

  // Mocking Application Rhythm
  const chartData = [
    { label: 'MON', value: 45 },
    { label: 'TUE', value: 82 },
    { label: 'WED', value: 68 },
    { label: 'THU', value: 95 },
    { label: 'FRI', value: 55 },
    { label: 'SAT', value: 25 },
    { label: 'SUN', value: 12 },
  ];

  if (authLoading || (!stats && loading)) {
    return (
      <div className="space-y-12 animate-pulse">
        <div className="h-12 w-64 bg-white/5 rounded-xl" />
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          {[1, 2, 3, 4].map(i => <div key={i} className="h-32 bg-white/5 rounded-2xl" />)}
        </div>
        <div className="h-96 bg-white/5 rounded-2xl" />
      </div>
    );
  }

  return (
    <div className="space-y-12 pb-24">
      
      <FadeIn>
        <div className="flex flex-col gap-2">
          <h1 className="text-4xl md:text-5xl font-black text-white tracking-tighter uppercase leading-none">
            Governance
          </h1>
          <p className="text-xs text-[#888888] tracking-widest uppercase font-bold">
            SYSTEM_STATUS: OPERATIONAL_LEVEL_01
          </p>
        </div>
      </FadeIn>

      {/* KPI Stats */}
      <StaggerContainer className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StaggerItem>
          <DashboardCard
            title="Active Requisitions"
            value={stats?.totalApplications || 0}
            subtitle="CANDIDATE_POOL_SIZE"
            variant="orange"
            trend={{ value: '8%', isUp: true }}
            icon={
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
              </svg>
            }
          />
        </StaggerItem>
        <StaggerItem>
          <DashboardCard
            title="Academic Modules"
            value={stats?.totalCourses || 0}
            subtitle="DEPLOYED_PROGRAMS"
            variant="blue"
            icon={
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
              </svg>
            }
          />
        </StaggerItem>
        <StaggerItem>
          <DashboardCard
            title="Assessment Logs"
            value={stats?.totalResults || 0}
            subtitle="EVALUATION_SESSIONS"
            variant="teal"
            trend={{ value: '142', isUp: true }}
            icon={
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
              </svg>
            }
          />
        </StaggerItem>
        <StaggerItem>
          <DashboardCard
            title="Archival Assets"
            value={stats?.totalMaterials || 0}
            subtitle="TOTAL_RESOURCES"
            variant="purple"
            icon={
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 19a2 2 0 01-2-2V7a2 2 0 012-2h4l2 2h4a2 2 0 012 2v1M5 19h14a2 2 0 002-2v-5a2 2 0 00-2-2H9a2 2 0 00-2 2v5a2 2 0 01-2 2z" />
              </svg>
            }
          />
        </StaggerItem>
      </StaggerContainer>

      <div className="grid lg:grid-cols-1 gap-8">
        <FadeIn>
          <DashboardChart 
            title="Application Inflow"
            subtitle="Visualizing candidate interest over the current archival cycle"
            data={chartData}
            color="#F97316"
          />
        </FadeIn>
      </div>

      <div className="grid lg:grid-cols-2 gap-8">
         <FadeIn>
            <div className="rounded-2xl border border-white/5 bg-[#0D0E12] p-8">
               <div className="flex justify-between items-center mb-8">
                  <h3 className="text-xl font-black text-white tracking-tight uppercase">Quick Actions</h3>
                  <span className="text-[10px] font-bold text-orange-400/40 uppercase tracking-widest">Administrative_Access</span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <button className="p-6 rounded-xl border border-white/5 bg-white/[0.02] hover:bg-white/[0.05] transition-all text-left group">
                     <span className="text-[9px] font-bold text-[#555555] uppercase tracking-widest block mb-2">01. DEPLOY</span>
                     <p className="text-xs font-black text-white group-hover:text-orange-400 transition-colors">NEW_COURSE</p>
                  </button>
                  <button className="p-6 rounded-xl border border-white/5 bg-white/[0.02] hover:bg-white/[0.05] transition-all text-left group">
                     <span className="text-[9px] font-bold text-[#555555] uppercase tracking-widest block mb-2">02. APPEND</span>
                     <p className="text-xs font-black text-white group-hover:text-orange-400 transition-colors">STUDY_MATERIAL</p>
                  </button>
                  <button className="p-6 rounded-xl border border-white/5 bg-white/[0.02] hover:bg-white/[0.05] transition-all text-left group">
                     <span className="text-[9px] font-bold text-[#555555] uppercase tracking-widest block mb-2">03. OVERSEE</span>
                     <p className="text-xs font-black text-white group-hover:text-orange-400 transition-colors">ALL_APPLICATIONS</p>
                  </button>
                  <button className="p-6 rounded-xl border border-white/5 bg-white/[0.02] hover:bg-white/[0.05] transition-all text-left group">
                     <span className="text-[9px] font-bold text-[#555555] uppercase tracking-widest block mb-2">04. ANALYZE</span>
                     <p className="text-xs font-black text-white group-hover:text-orange-400 transition-colors">RESULT_MATRICS</p>
                  </button>
               </div>
            </div>
         </FadeIn>

         <FadeIn>
            <div className="rounded-2xl border border-white/5 bg-gradient-to-br from-orange-500/10 to-transparent p-8 h-full">
               <h3 className="text-xl font-black text-white tracking-tight uppercase mb-8">System Health</h3>
               <div className="space-y-6">
                  <div className="flex items-center justify-between p-4 rounded-xl bg-white/[0.02] border border-white/5">
                     <div className="flex items-center gap-4">
                        <div className="w-2 h-2 rounded-full bg-teal-400 shadow-[0_0_10px_rgba(45,212,191,0.5)]" />
                        <span className="text-[10px] font-bold text-white uppercase tracking-widest">Database_Sync</span>
                     </div>
                     <span className="text-[9px] font-bold text-teal-400 uppercase tracking-widest">ACTIVE</span>
                  </div>
                  <div className="flex items-center justify-between p-4 rounded-xl bg-white/[0.02] border border-white/5">
                     <div className="flex items-center gap-4">
                        <div className="w-2 h-2 rounded-full bg-teal-400 shadow-[0_0_10px_rgba(45,212,191,0.5)]" />
                        <span className="text-[10px] font-bold text-white uppercase tracking-widest">Auth_Protocol</span>
                     </div>
                     <span className="text-[9px] font-bold text-teal-400 uppercase tracking-widest">SECURE</span>
                  </div>
                  <div className="flex items-center justify-between p-4 rounded-xl bg-white/[0.02] border border-white/5">
                     <div className="flex items-center gap-4">
                        <div className="w-2 h-2 rounded-full bg-orange-400 shadow-[0_0_10px_rgba(249,115,22,0.5)]" />
                        <span className="text-[10px] font-bold text-white uppercase tracking-widest">Resource_Load</span>
                     </div>
                     <span className="text-[9px] font-bold text-orange-400 uppercase tracking-widest">NOMINAL</span>
                  </div>
               </div>
            </div>
         </FadeIn>
      </div>

    </div>
  );
}
